// 100 classical Ayurvedic formulations sourced from Sahasrayogam, Ayurveda
// Formulary of India (AFI), and the standard Kerala pharmacopoeia. Maps to
// the existing AyurvedaFormulation model. Upsert by deterministic id so
// re-runs are idempotent. Malayalam names preserved as Unicode.

import type { PrismaClient } from '@prisma/client'

type Seed = {
  id:            string
  slug:          string
  name:          string                 // English
  sanskritName?: string | null
  malayalamName?: string | null
  classicalText: string                  // Sahasrayogam | AFI Part I | Ashtanga Hridayam | ...
  category:      string                  // existing model categories
  ingredients:   string[]
  primaryUses:   string[]
  doshaImpact?:  string | null
  typicalDose?:  string | null
  anupanaCommon?: string | null
  contraindications?: string | null
  manufacturers: string[]
  description:   string
}

