const DOSHA = (s: 'v' | 'p' | 'k' | 'vp' | 'vk' | 'pk' | 'tri'): string =>
  s === 'v' ? 'vata-pacifying' : s === 'p' ? 'pitta-pacifying' : s === 'k' ? 'kapha-pacifying'
  : s === 'vp' ? 'vata-pitta-pacifying' : s === 'vk' ? 'vata-kapha-pacifying' : s === 'pk' ? 'pitta-kapha-pacifying' : 'tridosha-balancing'
const DISC = '\n\nClassical formulation — consult a qualified Ayurveda doctor for personalised prescription, dose adjustment, and condition-specific suitability.'

