export async function seedFormularyV2(prisma: PrismaClient): Promise<{ count: number }> {
  for (const f of F) {
    const { id, ...data } = f
    await prisma.ayurvedaFormulation.upsert({
      where:  { id },
      update: data,
      create: { id, ...data },
    })
  }
  return { count: F.length }
}
